	}

	printk(BIOS_DEBUG,
	       "ATOMBIOS: select CRTC %d -> enc_id=0x%02x mode=%d%s\n",
	       crtc_id, enc_id, path->encoder_mode,
	       path->is_dac ? " (DAC)" : "");

	return atom_execute_table(ctx, cmd_idx.select_crtc_source,
				  (uint32_t *)&args,
				  sizeof(args));
}

